import{_ as o,o as a,c as t,ag as n}from"./chunks/framework.CbQjVMS6.js";const m=JSON.parse('{"title":"Powerpack.exe Command Line Options","description":"","frontmatter":{},"headers":[],"relativePath":"command-line-options.md","filePath":"command-line-options.md","lastUpdated":1774323326000}'),i={name:"command-line-options.md"};function s(l,e,r,p,c,d){return a(),t("div",null,[...e[0]||(e[0]=[n(`<h1 id="powerpack-exe-command-line-options" tabindex="-1">Powerpack.exe Command Line Options <a class="header-anchor" href="#powerpack-exe-command-line-options" aria-label="Permalink to &quot;Powerpack.exe Command Line Options&quot;">​</a></h1><p>Depending on your preferred workflow, there are several ways you can use Powerpack:</p><ol><li><p><strong>Watch the current folder</strong>: place <code>Powerpack.exe</code> in the same folder as your 8XP files and double-click it to run. It will monitor the current folder for any changes to 8XP or 8XPPP files, and as soon as it sees a modification, it will automatically process that changed file.</p></li><li><p><strong>Process specific files</strong>: by dropping 8XP files onto <code>Powerpack.exe</code> (or specifying them on the command line) only those files will be processed and then <code>Powerpack.exe</code> will exit.</p></li><li><p><strong>Watch another folder</strong>: by dropping any folder onto <code>Powerpack.exe</code> that folder will be watched for any changes to 8XP or 8XPPP files.</p></li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also do a combination of the above by dropping both files and a folder onto <code>Powerpack.exe</code>. The files will be immediately processed, and then the folder will be watched for further changes.</p></div><h2 id="command-line-examples" tabindex="-1">Command line examples <a class="header-anchor" href="#command-line-examples" aria-label="Permalink to &quot;Command line examples&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Powerpack.exe &quot;Path\\to\\MYPROG.8XP&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Powerpack.exe &quot;Path\\to\\MYPROG.8XP&quot; &quot;Path\\to\\MYPROG2.8XP&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Powerpack.exe &quot;Path\\to\\MYPROG.8XP&quot; &quot;Path\\to\\MyFolder&quot;</span></span></code></pre></div><p>You may compile <em>multiple</em> files with Powerpack, but only a <em>single</em> folder can be watched for changes. If you happen to specify multiple folders, only the first one will be used.</p><h2 id="other-options" tabindex="-1">Other options <a class="header-anchor" href="#other-options" aria-label="Permalink to &quot;Other options&quot;">​</a></h2><p>There are no other command line options as yet, but they will be coming soon!</p>`,9)])])}const u=o(i,[["render",s]]);export{m as __pageData,u as default};
